content:
{
  "sentences": [
    {
      "text": "這個衣服有瑕疵，我可以退貨嗎？",
      "pinyin": "Zhège yīfu yǒu xiácī, wǒ kěyǐ tuìhuò ma?",
      "pinyin_numeric": "zhe4 ge5 yi1 fu5 you3 xia2 ci1, wo3 ke3 yi3 tui4 huo4 ma0",
      "translation_en": "This clothing has a defect, can I return it?",
      "translation_ko": "이 옷에 하자가 있는데, 환불할 수 있나요?"
    },
    {
      "text": "如果尺寸不合，可以換貨嗎？",
      "pinyin": "Rúguǒ chǐcùn bù hé, kěyǐ huànhuò ma?",
      "pinyin_numeric": "ru2 guo3 chi3 cun4 bu4 he2, ke3 yi3 huan4 huo4 ma0",
      "translation_en": "If the size doesn't fit, can I exchange it?",
      "translation_ko": "사이즈가 맞지 않으면 교환할 수 있나요?"
    },
    {
      "text": "我買的鞋子壞掉了，可以退錢嗎？",
      "pinyin": "Wǒ mǎi de xiézi huài diào le, kěyǐ tuì qián ma?",
      "pinyin_numeric": "wo3 mai3 de5 xie2 zi5 huai4 diao4 le5, ke3 yi3 tui4 qian2 ma0",
      "translation_en": "The shoes I bought are broken, can I get a refund?",
      "translation_ko": "제가 산 신발이 고장 났는데, 환불받을 수 있나요?"
    },
    {
      "text": "這個手機有問題，我可以換新的嗎？",
      "pinyin": "Zhège shǒujī yǒu wèntí, wǒ kěyǐ huàn xīn de ma?",
      "pinyin_numeric": "zhe4 ge5 shou3 ji1 you3 wen4 ti2, wo3 ke3 yi3 huan4 xin1 de5 ma0",
      "translation_en": "This phone has a problem, can I exchange it for a new one?",
      "translation_ko": "이 핸드폰에 문제가 있는데, 새것으로 교환할 수 있나요?"
    },
    {
      "text": "我買的書髒掉了，可以退貨嗎？",
      "pinyin": "Wǒ mǎi de shū zāng diào le, kěyǐ tuìhuò ma?",
      "pinyin_numeric": "wo3 mai3 de5 shu1 zang1 diao4 le5, ke3 yi3 tui4 huo4 ma0",
      "translation_en": "The book I bought got dirty, can I return it?",
      "translation_ko": "제가 산 책이 더러워졌는데, 환불할 수 있나요?"
    },
    {
      "text": "這個顏色不對，我可以換貨嗎？",
      "pinyin": "Zhège yánsè bù duì, wǒ kěyǐ huànhuò ma?",
      "pinyin_numeric": "zhe4 ge5 yan2 se4 bu4 dui4, wo3 ke3 yi3 huan4 huo4 ma0",
      "translation_en": "This color is wrong, can I exchange it?",
      "translation_ko": "이 색상이 맞지 않는데, 교환할 수 있나요?"
    },
    {
      "text": "這個包包有破掉，可以退錢嗎？",
      "pinyin": "Zhège bāobāo yǒu pò diào, kěyǐ tuì qián ma?",
      "pinyin_numeric": "zhe4 ge5 bao1 bao1 you3 po4 diao4, ke3 yi3 tui4 qian2 ma0",
      "translation_en": "This bag is torn, can I get a refund?",
      "translation_ko": "이 가방이 찢어졌는데, 환불받을 수 있나요?"
    },
    {
      "text": "我買的褲子尺寸不合，可以換貨嗎？",
      "pinyin": "Wǒ mǎi de kùzi chǐcùn bù hé, kěyǐ huànhuò ma?",
      "pinyin_numeric": "wo3 mai3 de5 ku4 zi5 chi3 cun4 bu4 he2, ke3 yi3 huan4 huo4 ma0",
      "translation_en": "The pants I bought don't fit, can I exchange them?",
      "translation_ko": "제가 산 바지 사이즈가 안 맞는데, 교환할 수 있나요?"
    },
    {
      "text": "這個杯子髒掉了，我可以換一個嗎？",
      "pinyin": "Zhège bēizi zāng diào le, wǒ kěyǐ huàn yī ge ma?",
      "pinyin_numeric": "zhe4 ge5 bei1 zi5 zang1 diao4 le5, wo3 ke3 yi3 huan4 yi1 ge5 ma0",
      "translation_en": "This cup is dirty, can I exchange it for another one?",
      "translation_ko": "이 컵이 더러운데, 다른 것으로 교환할 수 있나요?"
    },
    {
      "text": "這個手機的型號不對，可以退貨嗎？",
      "pinyin": "Zhège shǒujī de xínghào bù duì, kěyǐ tuìhuò ma?",
      "pinyin_numeric": "zhe4 ge5 shou3 ji1 de5 xing2 hao4 bu4 dui4, ke3 yi3 tui4 huo4 ma0",
      "translation_en": "The model of this phone is wrong, can I return it?",
      "translation_ko": "이 핸드폰의 모델이 맞지 않는데, 환불할 수 있나요?"
    }
  ]
}
